function OrderButton() {
  const [isSubmitting, setIsSubmitting] = useState(false);

  async function handleSubmit() {
    if (isSubmitting) return; // 用旗標鎖住，避免重複觸發
    setIsSubmitting(true);
    await submitOrder();
    setIsSubmitting(false);
  }

  return <button onClick={handleSubmit} disabled={isSubmitting}>送出訂單</button>;
}

// 錯誤示範：繞過 React，直接操作 DOM
document.getElementById("greeting").textContent = "Hi";

// 正確做法：改變驅動畫面的 state，讓 React 重新渲染
function Greeting() {
  const [text, setText] = useState("Hello");
  return (
    <div>
      <p id="greeting">{text}</p>
      <button onClick={() => setText("Hi")}>改成 Hi</button>
    </div>
  );
}

